function solve(points: number[][]): number {
    const MOD = 10**9 + 7;
    const n = points.length;
    const yToX = new Map<number, number[]>();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!yToX.has(y)) {
            yToX.set(y, []);
        }
        yToX.get(y)!.push(x);
    }

    let result = 0;

    // Iterate through each y-coordinate
    for (const [y1, xs1] of yToX.entries()) {
        // Iterate through each y-coordinate greater than y1
        for (const [y2, xs2] of yToX.entries()) {
            if (y2 === y1) continue;

            // Count the number of common x-values between the two y-levels
            let common = 0;
            for (const x of xs1) {
                if (xs2.includes(x)) {
                    common++;
                }
            }

            // Calculate the number of ways to choose 2 points from each y-level
            // and multiply them to get the number of possible trapezoids
            const ways1 = (common * (common - 1)) / 2;
            const ways2 = (xs1.length * (xs1.length - 1)) / 2;
            const ways3 = (xs2.length * (xs2.length - 1)) / 2;

            result = (result + ways1 * ways2 * ways3) % MOD;
        }
    }

    return result;
}

